[Form]
public class DocPrintMgmtUtils extends FormRun
{
    DocPrintMgmtUtilsTmp tmpTable;
    DocPrintMgmtInfoTmp infoTable = null;
    RecId printMgmtSettingsRecId;

    Map fieldGroupsVisibilityMap;
    container fieldGroupsVisibilityContainer;

    // Needed for handling the working copy
    container workingCopyPrintJobSettings;
    PrintMgmtReportFormatName workingCopyFormatName;
    PrintMgmtDocumentType workingCopyDocumentType;

    boolean isWorkingCopySet;


    /* 
     * ----------------------------------------------------------------
     * SysLastValue START
     * ----------------------------------------------------------------
     */

    #define.CurrentVersion(1)
    #localmacro.CurrentList
        fieldGroupsVisibilityContainer
    #endmacro

}

private UserId lastValueUserId()
{
    return curUserId();
}

private UtilElementType lastValueType()
{
    return UtilElementType::Form;
}

private IdentifierName lastValueElementName()
{
    return this.name();
}

private IdentifierName lastValueDesignName()
{
    // Unique key: (user, company, type, elementName, designName)
    // We don't have such a need to save different sets of the form data.
    return '';
}

DataAreaId lastValueDataAreaId()
{
    return curext();
}

void initParmDefault()
{
    // Don't need to initialize any of the controls.
}

public container pack()
{
    this.getControlValuesForSysLastValues();
    return [#CurrentVersion, #CurrentList];
}

public boolean unpack(container _packedObject)
{
    Integer version = conPeek(_packedObject, 1);
    switch (version)
    {
        case #CurrentVersion:
            [version, #CurrentList] = _packedObject;
            break;
        default:
            return false;
    }
    return true;
}

void getControlValuesForSysLastValues()
{
    fieldGroupsVisibilityContainer = fieldGroupsVisibilityMap.pack();
}

void setControlValuesFromSysLastValues()
{
    if (fieldGroupsVisibilityContainer != conNull())
    {
        fieldGroupsVisibilityMap = Map::create(fieldGroupsVisibilityContainer);
    }
}

