/// <summary>
/// We need this implementation to interface with the DocPrinterSelector form,
/// which is a printer lookup form. When called from the Printer print destination
/// we want to cache the printer list in the caller form, but when called
/// from this form, we don't want the caching, because we want to build the printer list
/// each time when the lookup is opened. So this method simply always returns null,
/// thus forcing the printer list to be re-built from scratch while opening
/// the printer lookup form.
/// </summary>
/// <param name = "_tmpPrinterList">Ignored.</param>
/// <returns>DocPrinterSelectorTmp buffer set to null</returns>
public DocPrinterSelectorTmp parmPrinterList_DC(DocPrinterSelectorTmp _tmpPrinterList = null)
{
    return null;
}

