{
    return workingCopyPrintJobSettings;
}

/// <summary>
/// Called when Print mgmt setup form is closed.
/// It does the following:
///     - Updates the form datasource to reflect the changes in the Print mgmt setup form,
///     - Refreshes the form.
/// </summary>
public void printMgmtSetupUIClosed()
{
    #Task

    // Update the form datasource to be in sync with the actual Print mgmt,
    // which might have been modified. 
    DocPrintMgmtUtilsTmp::fillTableWithAllSettings(tmpTable, infoTable); 

    // Refresh the datasource.
    element.task(#taskRefresh);
}

/// <summary>
/// Get the names of all field groups in the main form grid, together with
/// the field group visibility.
/// </summary>
/// <returns>Map of field group names and their current visibilities.</returns>
public Map getFieldGroups()
{
    return fieldGroupsVisibilityMap;
}

/// <summary>
/// Get the key value for the Map where field group names and visibilities are stored.
/// Key is formed from the 2-digit index by which the field group appears in the form and
/// the field group name, separated by a dot (for the readability, if needed).
/// Using such keys enables listing the field groups in the same order as they appear
/// in the form. If we would use only field group names, then the field groups  in the lookup
/// would be sorted alphabetically based on their names.
/// </summary>
/// <param name = "_fc">FormControl field group</param>
/// <param name = "_index">int order of appearance of the field group in the form</param>
/// <returns>str key value to be used in the Map.</returns>
public str formControl2Key(FormControl _fc, int _index)
{
    return strRFix(int2str(_index), 2, '0') + '.' + _fc.labelText();
}

/// <summary>
/// Initialize the Map with field group names and their visibilities (true)
/// if we didn't get it from the SysLastValue (first opening of form).
/// Then apply that configuration to the field groups in the form.
/// </summary>
public void initFieldGroupsVisibility()
{
    if (fieldGroupsVisibilityMap == null)
    {
        fieldGroupsVisibilityMap = new Map(Types::String, Types::Enum);

        for (int i = 1; i <= Grid.controlCount(); i++)
        {
            FormControl fc = Grid.controlNum(i);

            //str groupName = fc.name();
            //if (groupName == 'RecordStatus' || groupName == 'PrintMgmtSetupId')
            //{
            //    // Skip some identification groups (we want to show them always)
            //    continue;
            //}
            fieldGroupsVisibilityMap.add(element.formControl2Key(fc, i), true);
        }
    }

    this.setFieldGroupsVisibility(false, fieldGroupsVisibilityMap);
}

/// <summary>
/// Set the visibility of field groups in the main form grid based on the provided Map, 
/// or set all field groups to visible if _all parameter is true.
/// </summary>
/// <param name = "_all">boolean, if true then all field groups are set to visible
/// and the second parameter is ignored. If it is false, then the information 
/// from the second parameter is used to set only the selected field groups
/// to visible.</param>
/// <param name = "_fieldGroups">Map of field group names and visibilities
/// to be set on them. If first parameter is true, then this Map is ignored.
/// It is used only if the first parameter is false.</param>
public void setFieldGroupsVisibility(boolean _all, Map _fieldGroups)
{
    for (int i = 1; i <= Grid.controlCount(); i++)
    {
        FormControl fc = Grid.controlNum(i);
        str mapKey = element.formControl2Key(fc, i);
        if (_all)
        {
            fc.visible(true);
        }
        else if (_fieldGroups.exists(mapKey))
        {
            fc.visible(_fieldGroups.lookup(mapKey));
        }

        // Overwrite the previous key-value par, it is the fastest way to set new visibility value
        // on the existing key.
        if (fieldGroupsVisibilityMap.exists(mapKey))
        {
            fieldGroupsVisibilityMap.add(mapKey, fc.visible());
        } 
    }
}

public void initInfoTable()
{
    if (infoTable == null)
    {        
        DocPrintMgmtInfo infoHelper = DocPrintMgmtInfo::construct(true);
        infoTable = infoHelper.getInfoTable();
    }
}

public void init()
{
    super();

    // Populate the PrintMgmtReportFormat table for the current company.
    DocPrintMgmtHelper::populatePrintMgmtReportFormat();

    // Populate the InfoTable.
    element.initInfoTable();

    // Get the values stored via SysLastValue framework.
    xSysLastValue::getLast(this);
    this.setControlValuesFromSysLastValues();

    // Init field groups visibility if needed
    this.initFieldGroupsVisibility();
}

public void close()
{
    xSysLastValue::saveLast(this);
    super();
}

public void enableControls()
{
    // Enable the SSRS or Docentric file type in Docentric File and Email
    // print destination depending on the template type (Doc/SSRS)
    boolean isDocentricDesign = !DocPrintMgmtUtilsTmp.useSrsBuiltInDesign();
    element.control(element.controlId(formControlStr(DocPrintMgmtUtils, DocentricFile_DestDocFileFormat))).enabled(isDocentricDesign);
    element.control(element.controlId(formControlStr(DocPrintMgmtUtils, DocentricFile_DestDocFileFormatSrs))).enabled(!isDocentricDesign);
    element.control(element.controlId(formControlStr(DocPrintMgmtUtils, DocentricEmail_DestDocEmailAttachmentFileFormat))).enabled(isDocentricDesign);
    element.control(element.controlId(formControlStr(DocPrintMgmtUtils, DocentricEmail_DestDocEmailAttachmentFileFormatSrs))).enabled(!isDocentricDesign);

    // Enable Email templates lookup
    element.control(element.controlId(formControlStr(DocPrintMgmtUtils, DocentricEmail_DestDocEmailTemplateId))).enabled(DocPrintMgmtUtilsTmp.DestDocEmailUseEmailTemplate);
}

public void init()
{
    super();

    element.initInfoTable();

    // Trick to initialize the tmpTable buffer reference.
    // Without it (or some select or similar), linkPhysicalTableInstance() wouldn't work,
    // but it also wouldn't report any problem.
    delete_from tmpTable;

    DocPrintMgmtUtilsTmp::fillTableWithAllSettings(tmpTable, infoTable);
    DocPrintMgmtUtilsTmp.linkPhysicalTableInstance(tmpTable);
}

public void displayOption(Common _record, FormRowDisplayOption _options)
{
    // Mark dirty records with light yellow color, 
    // records marked for deletion with light red color, 
    // others are white.
    DocPrintMgmtUtilsTmp currentRecord = _record.data();
    if (currentRecord.RecordStatus == DocPrintMgmtUtilsRecordStatus::Dirty)
    {
        _options.backColor(0xFFF4CE);   // yellow color from infolog warning
    }
    else if (currentRecord.RecordStatus == DocPrintMgmtUtilsRecordStatus::MarkForDeletion)
    {
        _options.backColor(0xFDE7E9);   // red color from infolog error
    }
    else
    {
        _options.backColor(0xFFFFFF);   // white color
    }

    super(_record, _options);
}

public int active()
{
    int ret;

    ret = super();

    // Enable the SSRS or Docentric file type in Docentric File and Email
    // print destination depending on the template type (Doc/SSRS)
    element.enableControls();       

    return ret;
}

public boolean leaveRecord(boolean _forceUpdate = false)
{
    #Task

    boolean ret;

    ret = super(_forceUpdate);            

    // If unpacked values were last modified, sync the packed values with them.
    DocPrintMgmtUtilsTmp currentRecord = DocPrintMgmtUtilsTmp::find(DocPrintMgmtUtilsTmp.RecId, tmpTable, true);
    if (currentRecord.LastModifiedSetting == DocPrintMgmtUtilsLastModifiedSetting::Unpacked)
    {
        ttsbegin;
        DocPrintMgmtUtilsHelper::packAndSavePrintDestinationSettings(currentRecord);
        currentRecord.update();
        ttscommit;

        // Force marking the record as dirty (yellow color).
        element.task(#taskRefresh);
    }

    return ret;
}

public void modified()
{
    super();

    // Enable/disable the Email template Id field
    element.enableControls();
}

public void modified()
{
    super();

    // Enable the SSRS or Docentric file type in Docentric File and Email
    // print destination depending on the template type (Doc/SSRS)
    element.enableControls();
}

public void clicked()
{
    super();

    element.setFieldGroupsVisibility(true, null);
}

public void clicked()
{
    #Task

    super();

    // If unpacked values were last modified, sync the packed values with them.
    DocPrintMgmtUtilsTmp currentRecord = DocPrintMgmtUtilsTmp::find(DocPrintMgmtUtilsTmp.RecId, tmpTable, true);
    if (currentRecord.LastModifiedSetting == DocPrintMgmtUtilsLastModifiedSetting::Unpacked)
    {
        ttsbegin;
        DocPrintMgmtUtilsHelper::packAndSavePrintDestinationSettings(currentRecord);
        currentRecord.update();
        ttscommit;

        // Force marking the record as dirty (yellow color).
        element.task(#taskRefresh);
    }

    workingCopyPrintJobSettings = DocPrintMgmtUtilsTmp.PrintJobSettings; 
    workingCopyFormatName = DocPrintMgmtUtilsTmp.FormatName;
    workingCopyDocumentType = DocPrintMgmtUtilsTmp.DocInstanceDocumentType;

    // 'Edit Working copy' and 'Apply values from Working copy' are initially disabled,
    // we enable them when 'Copy to Working copy' is clicked for the first time.
    if (!isWorkingCopySet)
    {
        isWorkingCopySet = true;

        element.control(element.controlId(formControlStr(DocPrintMgmtUtils, EditWorkingCopyBtn))).enabled(true);
        element.control(element.controlId(formControlStr(DocPrintMgmtUtils, ApplyWorkingCopyMenuItem))).enabled(true);
    }
}

public void clicked()
{
    super();

    SRSPrintDestinationSettings pds = new SRSPrintDestinationSettings();
    pds.unpack(workingCopyPrintJobSettings);

    // Open the print destination settings form.
    boolean ok = DocPrintMgmtHelper::showSettingsDialog(pds, workingCopyFormatName, workingCopyDocumentType);

    // Print destination form closed, store the new setting in working copy container.
    if (ok)
    {
        // TODO: Validate the selected print destination

        workingCopyPrintJobSettings = pds.pack();
    }
}

public void clicked()
{
    super();

    if (DocPrintMgmtUtilsUIHelper::checkAndCleanupDirtyRecords(tmpTable))
    {
        DocPrintMgmtUtilsUIHelper::launchPrintMgmtSetup(DocPrintMgmtUtilsTmp, element, false);
    }    
}

public void clicked()
{
    super();

    if (DocPrintMgmtUtilsUIHelper::checkAndCleanupDirtyRecords(tmpTable))
    {
        DocPrintMgmtUtilsUIHelper::launchPrintMgmtSetup(DocPrintMgmtUtilsTmp, element, true);
    }
}
